_extract_code_span_references() {
    let source = "# Storage\n\nThe `QueryableStore` trait defines the interface.\n";
    let meta = SourceMetadata {
        file_path: "docs/storage.md".into(),
        extension: "md".into(),
        ..Default::default()
    };
    let chunker = MarkdownChunker::new();
    let result = chunker.chunk(source, &meta).unwrap();
    assert!(!result.relations.is_empty(), "Should extract QueryableStore reference");
    let rel = &result.relations[0];
    assert_eq!(rel.relation, "references");
    assert_eq!(rel.to_name, Some("QueryableStore".to_string()));
}

#[test]
fn test_extract_link_references() {
    let source = "# Traits\n\nSee [the traits file](src/traits.rs) for details.\n";
    let meta = SourceMetadata {
        file_path: "docs/overview.md".into(),
        extension: "md".into(),
        ..Default::default()
    };
    let chunker = MarkdownChunker::new();
    let result = chunker.chunk(source, &meta).unwrap();
    let file_refs: Vec<_> = result.relations.iter().filter(|r| !r.to_file.is_empty()).collect();
    assert!(!file_refs.is_empty(), "Should extract file path reference");
    assert!(file_refs[0].to_file.contains("traits.rs"));
}

